import { useMemo, useEffect } from "react";
import { useParams, useSearchParams, useLocation } from "react-router-dom";
import Header from "@/components/landing/Header";
import Footer from "@/components/landing/Footer";
import { Reveal } from "@/components/landing/motion";
import ItemDetailContent from "@/components/landing/ItemDetailContent";
import { useMarket } from "@/lib/MarketContext";
import { fmt } from "@/lib/parseItem";

const SITE_NAME = "Castia Market Insight";
const BASE_URL = "https://lektodesigns.github.io/castia-market-insight";

const DEFAULT_TITLE = SITE_NAME;
const DEFAULT_DESC =
  "Castia auction-house price tracker — median prices, confidence ratings, and IQR ranges refreshed every five minutes.";

function setMeta(name, value) {
  let el = document.querySelector(`meta[property="${name}"], meta[name="${name}"]`);
  if (el) el.setAttribute("content", value);
}

export default function ItemDetail() {
  const { key: rawKey } = useParams();
  const [searchParams, setSearchParams] = useSearchParams();
  const location = useLocation();
  const { market } = useMarket();

  const itemKey = useMemo(() => {
    try { return decodeURIComponent(rawKey || ""); } catch { return rawKey || ""; }
  }, [rawKey]);

  const item = useMemo(() => {
    if (!market?.rows?.length || !itemKey) return null;
    const idx = market.rowsByKey;
    // Try exact match first
    if (idx.has(itemKey)) return idx.get(itemKey);
    // Case-insensitive fallback: find by lowercase key
    const lowerKey = itemKey.toLowerCase();
    for (const [k, row] of idx.entries()) {
      if (k.toLowerCase() === lowerKey) return row;
    }
    return null;
  }, [market, itemKey]);

  useEffect(() => {
    if (!item) {
      document.title = DEFAULT_TITLE;
      return;
    }
    const name = item.name || itemKey;
    const median = item.median ? fmt(item.median) : null;
    const desc = `View ${name} prices on Castia Market — ${median ? `median ${median}` : "real-time pricing"}${item.confidence ? `, ${item.confidence} confidence` : ""}.`;
    const title = `${name} · ${SITE_NAME}`;
    const url = `${BASE_URL}${location.pathname}${location.search}`;

    document.title = title;
    setMeta("og:title", title);
    setMeta("og:description", desc);
    setMeta("og:url", url);
    setMeta("twitter:title", title);
    setMeta("twitter:description", desc);
    setMeta("twitter:card", "summary_large_image");

    let canonical = document.querySelector("link[rel='canonical']");
    if (!canonical) {
      canonical = document.createElement("link");
      canonical.rel = "canonical";
      document.head.appendChild(canonical);
    }
    canonical.href = url;

    return () => {
      document.title = DEFAULT_TITLE;
      setMeta("og:title", DEFAULT_TITLE);
      setMeta("og:description", DEFAULT_DESC);
      setMeta("twitter:title", DEFAULT_TITLE);
      setMeta("twitter:description", DEFAULT_DESC);
    };
  }, [item, itemKey, location.pathname, location.search]);

  const openSeller = (name) => {
    const next = new URLSearchParams(searchParams);
    next.set("sellerView", name);
    setSearchParams(next);
  };

  return (
    <div data-testid="item-detail-page" className="min-h-screen bg-bg-base text-white font-body">
      <Header />
      <main className="pt-24 pb-16">
        <Reveal className="max-w-4xl mx-auto px-6 md:px-12">
          <ItemDetailContent itemKey={itemKey} onOpenSeller={openSeller} />
        </Reveal>
      </main>
      <Footer />
    </div>
  );
}
